import React, { useState } from "react";
import { XMarkIcon } from "@heroicons/react/24/solid";

export default function AddTask({ closeModal, onTaskAdded }) {
  const [formData, setFormData] = useState({
    title: "",
    dueDate: "",
    priority: "MEDIUM",
    category: "",
    completed: false,
  });

  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");
  const [loadingAI, setLoadingAI] = useState(false);

  const handleChange = (e) => {
    const { name, value, type, checked } = e.target;
    setFormData({
      ...formData,
      [name]: type === "checkbox" ? checked : value,
    });
  };

  // 🤖 AI Generate
  const handleAIGenerate = async () => {
    setLoadingAI(true);
    setError("");

    try {
      const res = await fetch("http://localhost:8086/tasks/ai-generate", {
        method: "POST",
      });

      const data = await res.json();

      setFormData({
        ...formData,
        title: data.title || "",
        dueDate: data.dueDate || "",
        priority: data.priority || "MEDIUM",
        category: data.category || "",
      });
    } catch (err) {
      setError("AI generation failed");
    } finally {
      setLoadingAI(false);
    }
  };

  const handleAdd = async (e) => {
    e.preventDefault();
    setError("");
    setSuccess("");

    if (!formData.title || !formData.dueDate) {
      setError("Please fill required fields");
      return;
    }

    try {
      const res = await fetch("http://localhost:8086/tasks", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          ...formData,
          autoGenerated: false,
          suggestionSource: "AI",
          notified: false,
        }),
      });

      if (res.ok) {
        setSuccess("Task added successfully!");
        if (onTaskAdded) onTaskAdded();
        setTimeout(() => closeModal(), 1000);
      } else {
        setError("Server error");
      }
    } catch (err) {
      setError("Server error");
    }
  };

  return (
    <div className="w-full max-w-md sm:w-[420px] p-6 sm:p-8 rounded-2xl backdrop-blur-xl bg-white/20 border border-white/30 shadow-2xl relative">
      {/* Close */}
      <button
        onClick={closeModal}
        className="absolute top-3 right-3 text-white"
      >
        <XMarkIcon className="w-6 h-6" />
      </button>

      <h2 className="text-2xl font-bold text-white text-center mb-4">
        Add Task
      </h2>

      {/* AI Generate */}
      <button
        type="button"
        onClick={handleAIGenerate}
        className="w-full mb-4 py-2 rounded-lg bg-purple-500/70 hover:bg-purple-600 text-white font-semibold transition"
      >
        {loadingAI ? "Analyzing..." : "🤖 Generate Task"}
      </button>

      {success && <p className="text-green-300 text-center mb-2">{success}</p>}
      {error && <p className="text-red-300 text-center mb-2">{error}</p>}

      <form onSubmit={handleAdd} className="space-y-4">

        {/* Title - Normal Input */}
        <input
          type="text"
          name="title"
          placeholder="Task Title"
          value={formData.title}
          onChange={handleChange}
          className="w-full px-4 py-2 rounded-lg border border-gray-400 text-black placeholder-black focus:outline-none focus:ring-2 focus:ring-purple-400"
        />

        {/* Due Date - Floating Border Placeholder */}
        <div className="relative w-full">
          <input
            type="date"
            name="dueDate"
            id="dueDate"
            value={formData.dueDate}
            onChange={handleChange}
            placeholder=" "
            className="peer w-full px-4 py-2 rounded-lg border border-gray-400 text-black placeholder-transparent focus:outline-none focus:ring-2 focus:ring-purple-400"
          />
          <label
            htmlFor="dueDate"
            className="absolute left-4 top-2 text-gray-500 text-sm transition-all
                       peer-placeholder-shown:top-2.5 peer-placeholder-shown:text-black peer-placeholder-shown:text-base
                       peer-focus:top-0 peer-focus:text-purple-400 peer-focus:text-sm"
          >
            Due Date
          </label>
        </div>

        {/* Priority - Normal Select */}
        <select
          name="priority"
          value={formData.priority}
          onChange={handleChange}
          className="w-full px-4 py-2 rounded-lg border border-gray-400 text-black bg-white/30 focus:outline-none focus:ring-2 focus:ring-purple-400"
        >
          <option value="LOW">Low</option>
          <option value="MEDIUM">Medium</option>
          <option value="HIGH">High</option>
        </select>

        {/* Category - Floating Border Placeholder */}
        <div className="relative w-full">
          <input
            type="text"
            name="category"
            id="category"
            value={formData.category}
            onChange={handleChange}
            placeholder=" "
            className="peer w-full px-4 py-2 rounded-lg border border-gray-400 text-black placeholder-transparent focus:outline-none focus:ring-2 focus:ring-purple-400"
          />
          <label
            htmlFor="category"
            className="absolute left-4 top-2 text-gray-500 text-sm transition-all
                       peer-placeholder-shown:top-2.5 peer-placeholder-shown:text-black peer-placeholder-shown:text-base
                       peer-focus:top-0 peer-focus:text-purple-400 peer-focus:text-sm"
          >
            Category
          </label>
        </div>

        <button
          type="submit"
          className="w-full py-2 rounded-lg bg-white/30 hover:bg-white/40 text-black font-semibold"
        >
          Add Task
        </button>
      </form>
    </div>
  );
}
